/** Client-side panel view filters (catalog scope stays on the server). */

import { $ } from "./utils.js";

function readFlag(id) {
  return Boolean(document.getElementById(id)?.checked);
}

export function panelFilterFlags() {
  return {
    visaOnly: readFlag("visaOnly"),
    hideApplied: readFlag("hideApplied"),
    hideEmpty: readFlag("hideEmpty"),
    notAppliedOnly: readFlag("notAppliedOnly"),
    hidePositionApplied: readFlag("hidePositionApplied"),
    hidePositionRejected: readFlag("hidePositionRejected"),
    positionAppliedOnly: readFlag("positionAppliedOnly"),
    positionRejectedOnly: readFlag("positionRejectedOnly"),
    positionLookingToApplyOnly: readFlag("positionLookingToApplyOnly"),
    fetchOkOnly: readFlag("fetchOkOnly"),
    fetchProblemOnly: readFlag("fetchProblemOnly"),
  };
}

function includeJobForPanelFilters(job, flags) {
  const applied = Boolean(job?.applied);
  const rejected = Boolean(job?.rejected);
  const lookingToApply = Boolean(job?.looking_to_apply);
  if (flags.hidePositionApplied && applied) return false;
  if (flags.hidePositionRejected && rejected) return false;
  if (flags.positionAppliedOnly && !applied) return false;
  if (flags.positionRejectedOnly && !rejected) return false;
  if (flags.positionLookingToApplyOnly && !lookingToApply) return false;
  return true;
}

function filterOpenJobs(jobs, flags) {
  let list = Array.isArray(jobs) ? jobs : [];
  if (flags.visaOnly) {
    list = list.filter((job) => job.visa_sponsorship === true);
  }
  return list.filter((job) => includeJobForPanelFilters(job, flags));
}

function filterRejectedJobs(jobs, flags) {
  let list = Array.isArray(jobs) ? jobs : [];
  if (flags.hidePositionRejected) return [];
  if (flags.visaOnly) {
    list = list.filter((job) => job.visa_sponsorship === true);
  }
  return list.filter((job) => includeJobForPanelFilters(job, flags));
}

function companyViewRow(company, flags) {
  const jobs = filterOpenJobs(company.jobs, flags);
  const rejectedJobs = filterRejectedJobs(company.rejected_jobs, flags);
  const notForMeJobs = company.not_for_me_jobs || company.hidden_jobs || [];
  const positionsApplied = jobs.filter((job) => job.applied).length;
  return {
    ...company,
    jobs,
    rejected_jobs: rejectedJobs,
    not_for_me_jobs: notForMeJobs,
    job_count: jobs.length,
    positions_applied: positionsApplied,
    positions_rejected: rejectedJobs.length,
    positions_not_for_me: notForMeJobs.length,
  };
}

function includeCompany(view, flags) {
  if (flags.hideApplied && view.company_applied) return false;
  if (flags.fetchOkOnly && !(view.fetch_ok && !view.fetch_problem)) return false;
  if (flags.fetchProblemOnly && !view.fetch_problem) return false;
  if (flags.visaOnly && !view.jobs.length && !view.rejected_jobs.length) return false;
  if (flags.positionRejectedOnly && !view.rejected_jobs.length) return false;
  if ((flags.positionAppliedOnly || flags.positionLookingToApplyOnly) && !view.jobs.length) {
    return false;
  }
  if (
    flags.hideEmpty
    && !view.jobs.length
    && !view.not_for_me_jobs.length
    && !view.rejected_jobs.length
  ) {
    return false;
  }
  if (flags.notAppliedOnly && (view.company_applied || !view.jobs.length)) return false;
  return true;
}

export function applyPanelFilters(catalog, flags = panelFilterFlags()) {
  return (catalog || [])
    .map((company) => companyViewRow(company, flags))
    .filter((view) => includeCompany(view, flags));
}

export function computeViewStats(companies, meta = {}) {
  let totalJobs = 0;
  let visaSponsored = 0;
  let positionsRejected = 0;
  let notForMe = 0;
  let companiesApplied = 0;
  let latestJobFetch = "";

  for (const company of companies || []) {
    totalJobs += company.job_count ?? company.jobs?.length ?? 0;
    positionsRejected += company.positions_rejected ?? company.rejected_jobs?.length ?? 0;
    notForMe += company.positions_not_for_me ?? company.not_for_me_jobs?.length ?? 0;
    if (company.company_applied || (company.positions_applied_all ?? company.positions_applied ?? 0) > 0) {
      companiesApplied += 1;
    }
    for (const job of company.jobs || []) {
      if (job.visa_sponsorship === true) visaSponsored += 1;
    }
    const fetchTs = (company.newest_job_fetched || company.latest_fetched || "").trim();
    if (fetchTs && fetchTs.localeCompare(latestJobFetch) > 0) {
      latestJobFetch = fetchTs;
    }
  }

  return {
    total_jobs: totalJobs,
    companies_with_jobs: companies.length,
    visa_sponsored: visaSponsored,
    applied: companiesApplied,
    positions_rejected: positionsRejected,
    not_for_me: notForMe,
    fetch_problems: meta.fetch_problem_total ?? 0,
    latest_job_fetch: latestJobFetch,
    latest_fetch_new_jobs: meta.latest_fetch_new_jobs ?? 0,
  };
}

export function mergeBoardStats(viewStats, userStats = {}) {
  return {
    ...viewStats,
    positions_applied: userStats.positions_applied ?? 0,
    positions_applied_today: userStats.positions_applied_today ?? 0,
    applied_today_jobs: userStats.applied_today_jobs || [],
    recent_fetch_runs: userStats.recent_fetch_runs || [],
    latest_fetch_new_jobs: userStats.latest_fetch_new_jobs ?? viewStats.latest_fetch_new_jobs ?? 0,
  };
}

/** Board load path: catalog from server, panel filters on the client. */

import { state } from "./state.js";
import { $ } from "./utils.js";
import { fetchBoard, fetchBoardUserStats } from "./api.js";
import { renderStats, renderCompanies, releaseCompanyOrder } from "./render.js";
import {
  applyPanelFilters,
  computeViewStats,
  mergeBoardStats,
} from "./board-filter.js";
import { showJobsLoading } from "./data.js";

function catalogScopeKey() {
  const country = $("country")?.value || "all";
  const ats = $("ats")?.value || "all";
  const location = $("location")?.value || "all";
  return `${country}|${ats}|${location}`;
}

function persistScopeSelection() {
  const country = $("country")?.value;
  if (country) localStorage.setItem("panel_country", country);
  if ($("ats")) localStorage.setItem("panel_ats", $("ats").value);
  if ($("location")) localStorage.setItem("panel_location", $("location").value);
}

export function applyBoardView() {
  state.allCompanies = applyPanelFilters(state.boardCatalog);
  const viewStats = computeViewStats(state.allCompanies, state.boardMeta || {});
  state.boardStats = mergeBoardStats(viewStats, state.boardUserStats || {});
  renderStats(state.boardStats);
  renderCompanies();
}

async function loadBoardCatalog(options = {}) {
  persistScopeSelection();
  const data = await fetchBoard(options);
  state.boardCatalog = data.companies || [];
  state.boardMeta = data.meta || {};
  state.boardScopeKey = catalogScopeKey();
}

async function loadBoardUserStats() {
  state.boardUserStats = await fetchBoardUserStats();
}

export async function loadBoard(options = {}) {
  if (!options.silent) releaseCompanyOrder();

  const scopeChanged = state.boardScopeKey !== catalogScopeKey();
  const needsCatalog = options.force || scopeChanged || !state.boardCatalog.length;

  if (needsCatalog) {
    if (!options.silent) showJobsLoading();
    await Promise.all([loadBoardCatalog(options), loadBoardUserStats()]);
  } else if (options.refreshUserStats) {
    await loadBoardUserStats();
  }

  applyBoardView();
}

export async function refreshBoardUserStats() {
  await loadBoardUserStats();
  applyBoardView();
}

export { catalogScopeKey };

from __future__ import annotations

from flask import g, jsonify, request

from relocation_jobs.core.auth import login_required
from relocation_jobs.db.fetch_runs import list_fetch_runs
from relocation_jobs.db.tracking import (
    count_jobs_applied as count_jobs_applied_db,
    count_jobs_applied_today as count_jobs_applied_today_db,
    list_jobs_applied_today as list_jobs_applied_today_db,
)
from relocation_jobs.services.catalog_service import flatten_companies
from relocation_jobs.web.helpers import catalog_scope_flags


def _catalog_board(scope, user_id):
    return flatten_companies(
        scope["country_key"],
        visa_only=False,
        hide_applied=False,
        hide_empty=False,
        not_applied_only=False,
        hide_position_applied=False,
        hide_position_rejected=False,
        position_applied_only=False,
        position_rejected_only=False,
        position_looking_to_apply_only=False,
        fetch_ok_only=False,
        fetch_problem_only=False,
        location=scope["location"],
        city=None,
        ats_type=scope["ats_type"],
        user_id=user_id,
    )


def register(app):
    @app.get("/api/board")
    @login_required
    def api_board():
        scope = catalog_scope_flags()
        companies, file_meta, fetch_problem_count = _catalog_board(scope, g.user_id)
        latest_fetch_new_jobs = sum(int(row.get("last_fetch_new_jobs") or 0) for row in file_meta)
        return jsonify({
            "companies": companies,
            "meta": {
                "country": request.args.get("country", "all"),
                "ats_type": scope["ats_type"],
                "location": scope["location"],
                "fetch_problem_total": fetch_problem_count,
                "latest_fetch_new_jobs": latest_fetch_new_jobs,
            },
        })

    @app.get("/api/board/stats")
    @login_required
    def api_board_stats():
        scope = catalog_scope_flags()
        timezone_name = (request.args.get("timezone") or "").strip() or None
        _, file_meta, _ = _catalog_board(scope, g.user_id)
        latest_fetch_new_jobs = sum(int(row.get("last_fetch_new_jobs") or 0) for row in file_meta)
        user_id = g.user_id
        country_key = scope["country_key"]
        return jsonify({
            "positions_applied": (
                count_jobs_applied_db(user_id, country=country_key) if user_id else 0
            ),
            "positions_applied_today": (
                count_jobs_applied_today_db(
                    user_id, country=country_key, timezone_name=timezone_name,
                )
                if user_id else 0
            ),
            "applied_today_jobs": (
                list_jobs_applied_today_db(
                    user_id, country=country_key, timezone_name=timezone_name,
                )
                if user_id else []
            ),
            "recent_fetch_runs": (
                list_fetch_runs(user_id, country=country_key, limit=5)
                if user_id else []
            ),
            "latest_fetch_new_jobs": latest_fetch_new_jobs,
        })

