import { notForMeReasonMeta } from "./constants";
import AtsScoreWidget from "./widgets/AtsScoreWidget";
import HideReasonPicker from "./widgets/HideReasonPicker";
import ReferralWidget from "./widgets/ReferralWidget";

function JobCityBadge({ job }) {
  const label = (job.job_city || job.location || "").trim();
  if (!label) return null;
  return <span className="badge job-city">{label}</span>;
}

function TitleRow({ job }) {
  return (
    <div className="position-title-row">
      <a className="job-title" href={job.url} target="_blank" rel="noopener noreferrer">{job.title}</a>
      <JobCityBadge job={job} />
    </div>
  );
}

function OpenJobCard({ job }) {
  const appliedHistory = job.applied_history || [];
  const appliedEvents = job.applied_events || [];
  const latestApplied = newestStatusDate(appliedHistory, job.applied_date || "");
  const appliedLabel = formatAppliedLabel({ date: latestApplied, at: job.applied_at || "" });
  const appliedTitle = formatAppliedHistoryTitle(appliedEvents.length ? appliedEvents : appliedHistory);
  const posCls = [
    job.applied ? " position-applied" : "",
    job.waiting_referral ? " position-waiting-referral" : "",
    job.looking_to_apply && !job.applied ? " position-looking-to-apply" : "",
    job.seen ? " position-seen" : "",
  ].join("");

  return (
    <div
      className={`position-card${posCls}`}
      data-country={job.country}
      data-company={job.company}
      data-url={job.url}
      data-idempotency-key={job.idempotency_key || ""}
    >
      <div className="position-top">
        <div className="position-head">
          <TitleRow job={job} />
          <div className="position-badges">
            {job.visa_sponsorship === true ? <span className="badge visa">Visa / relocation</span> : null}
            {job.applied ? (
              <span className="badge applied" title={appliedTitle ? `Applied on: ${appliedTitle}` : undefined}>
                {appliedLabel}
              </span>
            ) : null}
            {!job.applied && latestApplied ? (
              <span
                className="badge applied"
                title={formatAppliedHistoryTitle(appliedEvents.length ? appliedEvents : appliedHistory)}
              >
                {formatAppliedLabel({ date: latestApplied, at: job.applied_at || "" }, { before: true })}
              </span>
            ) : null}
            {job.waiting_referral && job.referral_linkedin_url ? (
              <a className="badge referral" href={job.referral_linkedin_url} target="_blank" rel="noopener noreferrer">Referrer</a>
            ) : job.waiting_referral ? (
              <span className="badge referral">Waiting referral</span>
            ) : null}
            {job.looking_to_apply && !job.applied ? (
              <span className="badge looking-to-apply">
                Looking to apply{job.looking_to_apply_date ? ` · ${job.looking_to_apply_date}` : ""}
              </span>
            ) : null}
            {job.seen ? (
              <span className="badge seen">Saw before{job.seen_date ? ` · ${job.seen_date}` : ""}</span>
            ) : null}
            <span className="badge date">{formatActivityBadge(jobActivityTs(job))}</span>
          </div>
        </div>
        <div className="position-side"><AtsScoreWidget job={job} /></div>
      </div>
      <div className="position-actions">
        {job.applied ? (
          <button type="button" className="applied-btn active" data-applied="1" title={appliedTitle ? `Applied on: ${appliedTitle}` : "Clear applied mark"}>
            {appliedLabel}
          </button>
        ) : (
          <button type="button" className="applied-btn" data-applied="0" title="Mark that you applied">I applied</button>
        )}
        <button type="button" className="rejected-btn" data-rejected="0" title="Mark that you got a rejection">Got rejection</button>
        {!job.applied && (
          job.looking_to_apply ? (
            <button type="button" className="looking-to-apply-btn active" data-looking="1" title="Clear looking-to-apply mark">
              Looking to apply{job.looking_to_apply_date ? ` · ${job.looking_to_apply_date}` : ""}
            </button>
          ) : (
            <button type="button" className="looking-to-apply-btn" data-looking="0" title="Mark as interested in applying">Looking to apply</button>
          )
        )}
        {job.seen ? (
          <button type="button" className="saw-before-btn active" data-seen="1" title="Clear saw-before mark">
            Saw before{job.seen_date ? ` · ${job.seen_date}` : ""}
          </button>
        ) : (
          <button type="button" className="saw-before-btn" data-seen="0" title="Mark that you saw this position before">Saw before</button>
        )}
        <ReferralWidget job={job} />
        {!job.applied ? <HideReasonPicker /> : null}
      </div>
    </div>
  );
}

function RejectedJobCard({ job }) {
  const rejectedHistory = job.rejected_history || [];
  const appliedHistory = job.applied_history || [];
  const appliedEvents = job.applied_events || [];
  const latestRejected = newestStatusDate(rejectedHistory, job.rejected_date || "");
  const latestApplied = newestStatusDate(appliedHistory, job.applied_date || "");
  const rejectedLabel = latestRejected ? `Rejected · ${latestRejected}` : "Rejected";
  const rejectedTitle = rejectedHistory.filter(Boolean).join(", ");
  const appliedTitle = formatAppliedHistoryTitle(appliedEvents.length ? appliedEvents : appliedHistory);

  return (
    <div
      className={`position-card rejected-role${job.seen ? " position-seen" : ""}`}
      data-country={job.country}
      data-company={job.company}
      data-url={job.url}
      data-idempotency-key={job.idempotency_key || ""}
    >
      <div className="position-top">
        <div className="position-head">
          <TitleRow job={job} />
          <div className="position-badges">
            <span className="badge rejected" title={rejectedTitle ? `Rejected on: ${rejectedTitle}` : undefined}>{rejectedLabel}</span>
            {latestApplied ? (
              <span className="badge applied" title={appliedTitle}>{formatAppliedLabel({ date: latestApplied, at: job.applied_at || "" })}</span>
            ) : null}
            {job.visa_sponsorship === true ? <span className="badge visa">Visa / relocation</span> : null}
            {job.seen ? <span className="badge seen">Saw before{job.seen_date ? ` · ${job.seen_date}` : ""}</span> : null}
            <span className="badge date">{formatActivityBadge(jobActivityTs(job))}</span>
          </div>
        </div>
        <div className="position-side"><AtsScoreWidget job={job} /></div>
      </div>
      <div className="position-actions">
        <button type="button" className="reapply-btn" title="Return to open positions so you can apply again">Reapply</button>
      </div>
    </div>
  );
}

function NotForMeJobCard({ job }) {
  const taggedDate = job.not_for_me_date ? ` · ${job.not_for_me_date}` : "";
  const { label: hideLabel, badgeCls: hideBadgeCls } = notForMeReasonMeta(job.not_for_me_reason);

  return (
    <div
      className="position-card not-for-me-role"
      data-country={job.country}
      data-company={job.company}
      data-url={job.url}
    >
      <div className="position-top">
        <div className="position-head">
          <TitleRow job={job} />
          <div className="position-badges">
            <span className={`badge ${hideBadgeCls}`}>{hideLabel}{taggedDate}</span>
            {job.visa_sponsorship === true ? <span className="badge visa">Visa / relocation</span> : null}
            <span className="badge date">{formatActivityBadge(jobActivityTs(job))}</span>
          </div>
        </div>
        <div className="position-side"><AtsScoreWidget job={job} /></div>
      </div>
      <div className="position-actions">
        <HideReasonPicker currentReason={job.not_for_me_reason || "not_for_me"} />
        <button type="button" className="restore-job-btn" title="Move back to applicable roles">Restore</button>
      </div>
    </div>
  );
}

function JobCard({ job, variant }) {
  if (variant === "rejected") return <RejectedJobCard job={job} />;
  if (variant === "not_for_me") return <NotForMeJobCard job={job} />;
  return <OpenJobCard job={job} />;
}

export default memo(JobCard);

import { memo } from "react";
import { companyActivityTs, formatActivityBadge, formatAppliedLabel } from "./format";
import { sortJobsForDisplay } from "./sort";
import JobCard from "./JobCard";

function companyKey(company) {
  return `${company.country}:${company.name}`;
}

function companyLocationLabels(company) {
  if (Array.isArray(company.locations) && company.locations.length) {
    return company.locations.map(
      (loc) => loc.label || `${loc.city} (${loc.country_label || loc.country})`,
    );
  }
  if (Array.isArray(company.cities) && company.cities.length) return company.cities;
  const single = (company.city || "").trim();
  if (!single) return [];
  return single.split(",").map((part) => part.trim()).filter(Boolean);
}

function formatCompanyCities(company) {
  const labels = companyLocationLabels(company);
  return labels.length ? labels.join(" · ") : "Set locations";
}

function emptyMessage(company, ui) {
  const rejectedCount = (company.rejected_jobs || []).length;
  if (company.job_count !== 0) return "No matching roles (try turning off visa filter).";
  if (company.stored_job_count > 0) {
    if (company.positions_not_for_me >= company.stored_job_count) {
      return "All roles marked not for me — click Show not for me jobs below.";
    }
    if (rejectedCount >= company.stored_job_count) {
      return "All roles marked rejected — click Show rejected jobs below.";
    }
    if (company.positions_hidden_by_visa > 0 && ui.visaOnly) {
      return "No visa / relocation roles in cache for this company.";
    }
    return "No roles match your current filters.";
  }
  return "No jobs yet — click Fetch jobs.";
}

function CompanyCard({ company, ui }) {
  const keyStr = companyKey(company);
  const collapsedSet = new Set(ui.collapsed || []);
  const showNotForMeSet = new Set(ui.showNotForMe || []);
  const showRejectedSet = new Set(ui.showRejected || []);
  const isCollapsed = collapsedSet.has(keyStr);
  const companyCls = [
    company.company_applied ? " company-applied" : "",
    company.awaiting_response ? " company-awaiting-response" : "",
    company.fetch_problem ? " fetch-problem" : "",
    company.fetch_ok && !company.fetch_problem ? " fetch-ok" : "",
  ].join("");
  const cityLabels = companyLocationLabels(company);
  const locationPayload = Array.isArray(company.locations) && company.locations.length
    ? company.locations
    : cityLabels.map((city) => ({ city }));
  const notForMeJobs = company.not_for_me_jobs || company.hidden_jobs || [];
  const notForMeCount = notForMeJobs.length;
  const rejectedCount = (company.rejected_jobs || []).length;
  const showingNotForMe = showNotForMeSet.has(keyStr);
  const showingRejected = showRejectedSet.has(keyStr) || ui.positionRejectedOnly;
  const isFetching = ui.fetchingCompanyKey === keyStr;
  const countLabel = company.job_count === 1 ? "1 role" : `${company.job_count} roles`;
  const appliedCount = company.positions_applied_all ?? company.positions_applied ?? 0;
  const openJobs = sortJobsForDisplay(company.jobs || []);

  return (
    <article
      className={`company-card${companyCls}${isCollapsed ? " collapsed" : ""}`}
      data-country={company.country}
      data-company={company.name}
    >
      <div className="company-header">
        <div>
          <div className="company-name-row">
            <div className="company-name">{company.name}</div>
            <button
              type="button"
              className="edit-name-btn"
              data-country={company.country}
              data-country-label={company.country_label || ""}
              data-company={company.name}
              title="Rename this company"
            >
              Rename
            </button>
          </div>
          <div className="company-meta">
            <button
              type="button"
              className="edit-city-btn"
              data-country={company.country}
              data-country-label={company.country_label || ""}
              data-company={company.name}
              data-locations={JSON.stringify(locationPayload)}
              data-has-cities={cityLabels.length ? "true" : "false"}
              title="Set or change company locations"
            >
              {formatCompanyCities(company)}
            </button>
            <span>{company.country_label}</span>
            <span>{countLabel}</span>
          </div>
          {company.careers_url ? (
            <div className="careers-row">
              <a className="job-title" href={company.careers_url} target="_blank" rel="noopener noreferrer" style={{ fontSize: "0.8rem", fontWeight: 500 }}>
                Careers page
              </a>
              <button
                type="button"
                className="edit-careers-btn"
                data-country={company.country}
                data-country-label={company.country_label || ""}
                data-company={company.name}
                data-url={company.careers_url}
                title="Fix wrong careers URL"
              >
                Edit URL
              </button>
            </div>
          ) : (
            <div className="careers-row">
              <span className="job-meta">No careers URL</span>
              <button
                type="button"
                className="edit-careers-btn"
                data-country={company.country}
                data-country-label={company.country_label || ""}
                data-company={company.name}
                data-url=""
                title="Add careers URL"
              >
                Edit URL
              </button>
            </div>
          )}
          <div className="company-toolbar">
            {company.awaiting_response ? (
              <button type="button" className="awaiting-response-btn active" data-awaiting="1" title="Clear awaiting-response mark">
                Awaiting response{company.awaiting_response_date ? ` · ${company.awaiting_response_date}` : ""}
              </button>
            ) : (
              <button type="button" className="awaiting-response-btn" data-awaiting="0" title="Waiting on application response(s) before applying to other roles here">
                Awaiting response
              </button>
            )}
            {notForMeCount > 0 ? (
              <button
                type="button"
                className={`show-not-for-me-btn${showingNotForMe ? " active" : ""}`}
                data-company-key={keyStr}
                title="Show jobs marked Not for me"
              >
                {showingNotForMe
                  ? "Hide not for me jobs"
                  : `Show ${notForMeCount} not for me job${notForMeCount === 1 ? "" : "s"}`}
              </button>
            ) : null}
            {rejectedCount > 0 ? (
              <button
                type="button"
                className={`show-rejected-btn${showingRejected ? " active" : ""}`}
                data-company-key={keyStr}
                title="Show jobs marked rejected"
              >
                {showingRejected
                  ? "Hide rejected jobs"
                  : `Show ${rejectedCount} rejected job${rejectedCount === 1 ? "" : "s"}`}
              </button>
            ) : null}
            {ui.scrapeEnabled ? (
              <button
                type="button"
                className="fetch-company-btn"
                data-country={company.country}
                data-company={company.name}
                disabled={ui.serverFetchRunning}
              >
                {isFetching ? "Fetching…" : "Fetch jobs"}
              </button>
            ) : null}
            <button
              type="button"
              className="remove-company-btn"
              data-country={company.country}
              data-company={company.name}
              title="Remove this company from the list"
            >
              Remove
            </button>
          </div>
        </div>
        <div className="company-header-side">
          <button type="button" className="collapse-company-btn" title="Hide or show roles under this company">
            {isCollapsed ? "Show positions" : "Hide positions"}
          </button>
          <span className="badge country">{company.country_label}</span>
          {company.company_applied ? (
            <span className="badge applied">
              {appliedCount > 1
                ? `${appliedCount} roles applied`
                : formatAppliedLabel({
                    date: company.company_applied_date || "",
                    at: company.company_applied_at || "",
                  })}
            </span>
          ) : null}
          {company.awaiting_response ? (
            <span className="badge awaiting-response">
              Awaiting response{company.awaiting_response_date ? ` · ${company.awaiting_response_date}` : ""}
            </span>
          ) : null}
          <span className="badge date">{formatActivityBadge(companyActivityTs(company))}</span>
        </div>
      </div>
      <div className="positions">
        {openJobs.length ? (
          openJobs.map((job) => <JobCard key={job.idempotency_key || job.url} job={job} variant="open" />)
        ) : (
          <div className="position-card"><span className="job-meta">{emptyMessage(company, ui)}</span></div>
        )}
        {showingRejected && rejectedCount > 0 ? (
          <>
            <div className="rejected-jobs-heading">Rejected jobs</div>
            {sortJobsForDisplay(company.rejected_jobs || []).map((job) => (
              <JobCard key={`r-${job.idempotency_key || job.url}`} job={job} variant="rejected" />
            ))}
          </>
        ) : null}
        {showingNotForMe && notForMeCount > 0 ? (
          <>
            <div className="not-for-me-jobs-heading">Not for me jobs</div>
            {sortJobsForDisplay(notForMeJobs).map((job) => (
              <JobCard key={`n-${job.idempotency_key || job.url}`} job={job} variant="not_for_me" />
            ))}
          </>
        ) : null}
      </div>
    </article>
  );
}

export default memo(CompanyCard, (prev, next) => (
  prev.company === next.company
