      <hr className="skeleton-divider" />
      <div className="skeleton-jobs">
        <div className="skeleton-block skeleton-job" />
        <div className="skeleton-block skeleton-job skeleton-job--short" />
      </div>
    </div>
  ));

  return <>{cards}</>;
}

import CompanyCard from "./CompanyCard";
import BoardSkeleton from "./BoardSkeleton";

export default function App({ view }) {
  if (view.loading) {
    return <BoardSkeleton />;
  }

  if (!view.companies?.length) {
    return (
      <div className="empty">
        No companies match your filters. Try another country or click <strong>Fetch new jobs</strong>.
      </div>
    );
  }

  return view.companies.map((company) => (
    <CompanyCard
      key={`${company.country}:${company.name}`}
      company={company}
      ui={view.ui}
    />
  ));
}

import { StrictMode, useCallback, useEffect, useState } from "react";
import { createRoot } from "react-dom/client";
import App from "./App";

function BoardRoot() {
  const [view, setView] = useState({ loading: true, companies: [], ui: {} });

  const setBoardView = useCallback((next) => {
    setView(next);
  }, []);

  useEffect(() => {
    window.relocationJobs = window.relocationJobs || {};
    window.relocationJobs.setBoardView = setBoardView;
    if (window.relocationJobs._pendingView) {
      setBoardView(window.relocationJobs._pendingView);
      window.relocationJobs._pendingView = null;
    }
  }, [setBoardView]);

  return <App view={view} />;
}

const mount = document.getElementById("jobs");
if (mount) {
  createRoot(mount).render(
    <StrictMode>
      <BoardRoot />
    </StrictMode>,
  );
}

