/** Bridge between vanilla fetch orchestration and the React fetch UI. */

export function publishFetchView(view) {
  const api = window.relocationJobs;
  if (api?.setFetchView) {
    api.setFetchView(view);
    return;
  }
  if (!window.relocationJobs) window.relocationJobs = {};
  window.relocationJobs._pendingFetchView = view;
}

/** Fetch header + panel view model for React. */

import { state } from "./state.js";
import { $ } from "./utils.js";
import { publishFetchView } from "./fetch-sync.js";

export const fetchPanelState = {
  open: false,
  title: "Fetching companies",
  subtitle: "Starting…",
  singleCompany: false,
  cancelHidden: true,
  cancelDisabled: false,
  cancelText: "Cancel",
  cancelTitle: "Stop fetching remaining companies",
  closeHidden: false,
  progressWrapHidden: true,
  progress: {
    current: 0,
    total: 0,
    pct: 0,
    label: "0 / 0 companies",
    companyLine: "",
  },
  activity: {
    hidden: true,
    step: "Starting…",
    detail: "",
    items: [],
  },
  log: {
    hidden: true,
    text: "",
    active: false,
  },
  review: {
    visible: false,
    hint: "",
    included: [],
    filtered: [],
    filteredExpanded: false,
    country: "",
    company: "",
    missingReview: false,
    addBtnVisible: false,
    expandHidden: true,
    expandLabel: "",
  },
  completion: {
    hidden: true,
    label: "Current run",
    started: "—",
    finished: "—",
    duration: "—",
    newJobs: "—",
  },
  footer: {
    hidden: true,
    pending: false,
    resolved: false,
    resolvedStatus: null,
    prompt: "Did the fetch work correctly?",
    country: "",
    company: "",
    okDisabled: false,
    problemDisabled: false,
  },
};

function countryLabelFromId(countryId) {
  const opt = [...($("country")?.options || [])].find((o) => o.value === countryId);
  return opt?.textContent?.trim() || countryId || "";
}

function buildHeaderState() {
  const controlsEnabled = Boolean(state.fetchControlsEnabled);
  const active = state.serverFetchRunning || state.countryFetchActive || state.fetchBusy;

  if (!controlsEnabled) {
    return { controlsEnabled: false, active: false, showButton: false, showChip: false };
  }

  if (!active) {
    return {
      controlsEnabled: true,
      active: false,
      showButton: true,
      showChip: false,
      buttonTitle: "Fetch jobs for the selected country and ATS filter",
    };
  }

  const summary = state.fetchJobSummary || {};
  let metaText = "Fetching…";
  let pct = 0;
  let chipTitle = "View fetch progress";

  if (state.fetchBusy && state.fetchingCompanyKey) {
    const company = state.fetchingCompanyKey.split(":").slice(1).join(":");
    metaText = company || "Fetching…";
    chipTitle = `View progress — ${company}`;
  } else if (summary.total > 0) {
    pct = Math.min(99, Math.round((summary.current / summary.total) * 100));
    metaText = `${summary.current}/${summary.total}`;
    chipTitle = `View progress — ${summary.current} of ${summary.total} companies (${pct}%)`;
    if (summary.company) {
      metaText = `${summary.current}/${summary.total} · ${summary.company}`;
      chipTitle += ` · ${summary.company}`;
    }
  } else if (summary.company) {
    metaText = summary.company;
    chipTitle = `View progress — ${summary.company}`;
  } else if (summary.countryLabel) {
    metaText = summary.countryLabel;
    chipTitle = `View progress — ${summary.countryLabel}`;
  }

  return {
    controlsEnabled: true,
    active: true,
    showButton: false,
    showChip: true,
    metaText,
    pct: Math.max(4, pct),
    chipTitle,
  };
}

export function publishFetchUi() {
  publishFetchView({
    header: buildHeaderState(),
    panel: fetchPanelState,
  });
}

export function patchFetchPanel(patch) {
  Object.assign(fetchPanelState, patch);
  publishFetchUi();
}

/** Fetch UI actions wired from React components. */

import { state } from "./state.js";
import { toast } from "./utils.js";
import { markFetchOk, toggleFetchProblem, addManualJobs } from "./api.js";
import { loadJobs } from "./data.js";
import {
  cancelFetch,
  ensureFetchPolling,
  handleFetchCountryClick,
  openFetchProgress,
} from "./scrape.js";
import {
  hideFetchPanel,
  setFetchReviewFeedbackDone,
  toggleFetchReviewFilteredExpanded,
} from "./render.js";

export function registerFetchActions() {
  window.relocationJobs = window.relocationJobs || {};
  window.relocationJobs.fetchActions = {
    startFetch: () => handleFetchCountryClick(),
    openProgress: () => openFetchProgress(),
    cancelFetch: () => cancelFetch(),
    closePanel: () => {
      hideFetchPanel();
      ensureFetchPolling();
    },
    toggleReviewExpand: () => toggleFetchReviewFilteredExpanded(),
    async submitReviewFeedback(country, company, action) {
      if (!country || !company) return;
      try {
        const result = action === "ok"
          ? await markFetchOk(country, company)
          : await toggleFetchProblem(country, company, true);
        if (!result) return;
        state.fetchReviewFeedback = { country, company, status: action === "ok" ? "ok" : "problem" };
        setFetchReviewFeedbackDone(state.fetchReviewFeedback.status);
        toast(action === "ok" ? `Fetch OK — ${company}` : `Fetch problem — ${company}`);
        await loadJobs({ silent: true });
        if (
          state.fetchReviewFeedback?.country === country
          && state.fetchReviewFeedback?.company === company
        ) {
          setFetchReviewFeedbackDone(state.fetchReviewFeedback.status);
        }
      } catch (err) {
        if (err?.message !== "auth") {
          toast(err?.message || "Could not save fetch status");
        }
        throw err;
      }
    },
    async addSelectedReviewJobs(country, company, selected) {
      if (!selected?.length) {
        toast("Select at least one role");
        return;
      }
      const result = await addManualJobs(country, company, selected);
      if (!result) return;
      toast(`Added ${result.added} role(s) to ${result.company}`);
      await loadJobs();
      hideFetchPanel();
    },
  };
}

import { memo } from "react";

function FetchHeader({ header = {} }) {
  if (!header.controlsEnabled) return null;

  if (header.showButton) {
    return (
      <button
        type="button"
        className="header-secondary-btn"
        title={header.buttonTitle || "Fetch jobs for the selected country and ATS filter"}
        onClick={() => window.relocationJobs?.fetchActions?.startFetch?.()}
      >
        <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
          <path d="M21 12a9 9 0 1 1-3-6.7" />
          <path d="M21 3v6h-6" />
        </svg>
        <span className="header-btn-text">Fetch</span>
      </button>
    );
  }

  if (!header.showChip) return null;

  return (
    <button
      type="button"
      className="header-secondary-btn fetch-progress-chip"
      title={header.chipTitle || "View fetch progress"}
      aria-label={header.chipTitle || "View fetch progress"}
      onClick={() => window.relocationJobs?.fetchActions?.openProgress?.()}
    >
      <span className="fetch-progress-chip-meter" aria-hidden="true">
        <span
          className="fetch-progress-chip-fill"
          style={{ width: `${header.pct || 4}%` }}
        />
      </span>
      <span className="header-btn-text">{header.metaText || "Fetching…"}</span>
      <svg className="fetch-progress-chip-chevron" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
        <path d="M9 18l6-6-6-6" />
      </svg>
    </button>
  );
}

export default memo(FetchHeader);

import { memo, useEffect, useMemo, useState } from "react";

const PREVIEW = 10;

function FetchPanel({ panel = {} }) {
  const [selected, setSelected] = useState(new Set());
  const open = Boolean(panel.open);

  useEffect(() => {
    document.body.classList.toggle("fetch-modal-open", open);
    return () => document.body.classList.remove("fetch-modal-open");
  }, [open]);

  useEffect(() => {
    setSelected(new Set());
  }, [panel.review?.country, panel.review?.company, panel.review?.filtered]);

  const filteredVisible = useMemo(() => {
    const filtered = panel.review?.filtered || [];
    if (panel.review?.filteredExpanded || filtered.length <= PREVIEW) return filtered;
    return filtered.slice(0, PREVIEW);
  }, [panel.review?.filtered, panel.review?.filteredExpanded]);

  const hiddenCount = Math.max(0, (panel.review?.filtered?.length || 0) - filteredVisible.length);

  if (!open) return null;

  const actions = window.relocationJobs?.fetchActions || {};
  const review = panel.review || {};
  const footer = panel.footer || {};
  const progress = panel.progress || {};
  const activity = panel.activity || {};
  const log = panel.log || {};
  const completion = panel.completion || {};

  function toggleJob(idx) {
    setSelected((prev) => {
      const next = new Set(prev);
      if (next.has(idx)) next.delete(idx);
      else next.add(idx);
      return next;
    });
  }

  async function onAddSelected() {
    const jobs = (review.filtered || []).filter((_, idx) => selected.has(idx));
    await actions.addSelectedReviewJobs?.(review.country, review.company, jobs);
  }

  return (
    <div
      className="dialog-backdrop fetch-panel-backdrop open"
      aria-hidden="false"
      onClick={(e) => {
        if (e.target === e.currentTarget) actions.closePanel?.();
      }}
    >
      <div className="fetch-panel" role="dialog" aria-modal="true" aria-labelledby="fetchTitle">
        <div className="fetch-panel-top">
          <div className="fetch-panel-title-wrap">
            <h2 className="fetch-panel-title" id="fetchTitle">{panel.title}</h2>
            <p className="fetch-panel-subtitle" id="fetchSubtitle">{panel.subtitle}</p>
            {!completion.hidden ? (
              <div className="fetch-completion" id="fetchCompletion">
                <p className="fetch-completion-label">{completion.label}</p>
                <dl className="fetch-completion-grid">
                  <div><dt>Started</dt><dd>{completion.started}</dd></div>
                  <div><dt>Finished</dt><dd>{completion.finished}</dd></div>
                  <div><dt>Duration</dt><dd>{completion.duration}</dd></div>
                  <div><dt>New roles</dt><dd>{completion.newJobs}</dd></div>
                </dl>
              </div>
            ) : null}
          </div>
          <div className="fetch-panel-actions">
            {!panel.cancelHidden ? (
              <button
                type="button"
                className="fetch-cancel-btn"
                disabled={panel.cancelDisabled}
                onClick={() => actions.cancelFetch?.()}
              >
                {panel.cancelText || "Cancel"}
              </button>
            ) : null}
            {!panel.closeHidden ? (
              <button
                type="button"
                className="fetch-close-btn"
                aria-label="Close panel"
                onClick={() => actions.closePanel?.()}
              >
                ×
              </button>
            ) : null}
          </div>
        </div>

        <div className="fetch-panel-body">
          {!panel.progressWrapHidden ? (
            <div className="fetch-progress-wrap">
              <div className="fetch-progress-meta">
                <span>{progress.label}</span>
                <span>{progress.pct}%</span>
              </div>
              <div
                className="fetch-progress-track"
                role="progressbar"
                aria-valuemin="0"
                aria-valuemax="100"
                aria-valuenow={progress.pct}
              >
                <div className="fetch-progress-bar" style={{ width: `${progress.pct}%` }} />
              </div>
              {progress.companyLine ? (
                <p className="fetch-current-company">{progress.companyLine}</p>
              ) : null}
            </div>
          ) : null}

          {!activity.hidden ? (
            <div className="fetch-activity">
              <div className="fetch-activity-current">
                <span className="fetch-activity-pulse" aria-hidden="true" />
                <div className="fetch-activity-copy">
                  <p className="fetch-activity-step">{activity.step}</p>
                  {activity.detail ? (
                    <p className="fetch-activity-detail">{activity.detail}</p>
                  ) : null}
                </div>
              </div>
              {activity.items?.length ? (
                <ol className="fetch-activity-log">
                  {activity.items.map((entry, idx) => (
                    <li key={`${entry.message}-${idx}`}>
                      <span className="fetch-activity-log-text">{entry.message}</span>
                      {entry.detail ? (
                        <span className="fetch-activity-log-meta">{entry.detail}</span>
                      ) : null}
                    </li>
                  ))}
                </ol>
              ) : null}
            </div>
          ) : null}

          {review.visible ? (
            <div className="fetch-review">
              {review.hint ? <p className="fetch-review-hint">{review.hint}</p> : null}
              <div className="fetch-review-section">
                <div className="fetch-review-section-head">
                  <h3 className="fetch-review-heading">
                    {review.filtered?.length
                      ? `Filtered out (${review.filtered.length})`
                      : "Filtered out (0)"}
                  </h3>
                  {review.addBtnVisible ? (
                    <button
                      type="button"
                      className="fetch-review-add-btn"
                      onClick={onAddSelected}
                    >
                      Add selected
                    </button>
                  ) : null}
                </div>
                <ul className="fetch-review-list fetch-review-checklist">
                  {filteredVisible.length ? filteredVisible.map((job, idx) => (
                    <li key={job.url || idx} className="fetch-review-item">
                      <label>
                        <input
                          type="checkbox"
                          className="fetch-review-check"
                          checked={selected.has(idx)}
                          onChange={() => toggleJob(idx)}
                        />
                        <span className="fetch-review-item-body">
                          <a href={job.url} target="_blank" rel="noopener noreferrer">
                            {job.title || job.url}
                          </a>
                          {job.filter_reason ? (
                            <span className="fetch-review-reason">{job.filter_reason}</span>
                          ) : null}
                        </span>
                      </label>
                    </li>
                  )) : (
                    <li className="fetch-review-item">
                      <span className="job-meta">{review.missingReview ? "No review data" : "None"}</span>
                    </li>
                  )}
                </ul>
                {!review.expandHidden ? (
                  <button
                    type="button"
                    className="fetch-review-expand-btn"
                    onClick={() => actions.toggleReviewExpand?.()}
                  >
                    {review.expandLabel}
                  </button>
                ) : null}
              </div>
              {review.included?.length ? (
                <div className="fetch-review-section">
                  <h3 className="fetch-review-heading">Matched ({review.included.length})</h3>
                  <ul className="fetch-review-list">
                    {review.included.map((job) => (
                      <li key={job.url} className="fetch-review-item">
                        <a href={job.url} target="_blank" rel="noopener noreferrer">
                          {job.title || job.url}
                        </a>
                      </li>
                    ))}
                  </ul>
                </div>
              ) : null}
            </div>
          ) : null}

          {!log.hidden ? (
            <pre className={`fetch-log${log.active ? " fetch-log-active" : ""}`}>{log.text}</pre>
          ) : null}
        </div>

        {!footer.hidden ? (
          <div className="fetch-panel-footer">
            <div className={`fetch-review-feedback${footer.pending ? " is-pending" : ""}${footer.resolved ? " is-resolved" : ""}`}>
              {!footer.resolved ? (
                <div className="fetch-review-feedback-prompt">
                  <span className="fetch-review-feedback-label">{footer.prompt}</span>
                  <div className="fetch-review-feedback-actions">
                    <button
                      type="button"
                      className="fetch-review-ok-btn"
                      disabled={footer.okDisabled}
                      onClick={() => actions.submitReviewFeedback?.(footer.country, footer.company, "ok")}
                    >
                      Yes, looks good
                    </button>
                    <button
                      type="button"
                      className="fetch-review-problem-btn"
                      disabled={footer.problemDisabled}
                      onClick={() => actions.submitReviewFeedback?.(footer.country, footer.company, "problem")}
                    >
                      No, fetch problem
                    </button>
                  </div>
                </div>
              ) : (
                <div className={`fetch-review-feedback-result is-${footer.resolvedStatus === "ok" ? "ok" : "problem"}`}>
                  <span className="fetch-review-feedback-text">
                    {footer.resolvedStatus === "ok" ? "Fetch confirmed OK" : "Marked as fetch problem"}
                  </span>
                </div>
              )}
            </div>
          </div>
        ) : null}
      </div>
    </div>
  );
}

export default memo(FetchPanel);

