/** Bridge between vanilla fetch orchestration and the React fetch UI. */

let fetchRevision = 0;

export function publishFetchView(view) {
  fetchRevision += 1;
  const payload = { ...view, rev: fetchRevision };
  const api = window.relocationJobs;
  if (api?.setFetchView) {
    api.setFetchView(payload);
    return;
  }
  if (!window.relocationJobs) window.relocationJobs = {};
  window.relocationJobs._pendingFetchView = payload;
}

import { StrictMode, useCallback, useEffect, useState } from "react";
import { createPortal } from "react-dom";
import { createRoot } from "react-dom/client";
import App from "./App";
import FetchHeader from "./FetchHeader";
import FetchPanel from "./FetchPanel";

function BoardRoot() {
  const [view, setView] = useState({ loading: true, companies: [], ui: {} });

  const setBoardView = useCallback((next) => {
    setView(next);
  }, []);

  useEffect(() => {
    window.relocationJobs = window.relocationJobs || {};
    window.relocationJobs.setBoardView = setBoardView;
    if (window.relocationJobs._pendingView) {
      setBoardView(window.relocationJobs._pendingView);
      window.relocationJobs._pendingView = null;
    }
  }, [setBoardView]);

  return <App view={view} />;
}

function FetchRoot() {
  const [fetchView, setFetchView] = useState({ header: {}, panel: {}, rev: 0 });

  const setFetchViewFn = useCallback((next) => {
    setFetchView({ ...next });
  }, []);

  useEffect(() => {
    window.relocationJobs = window.relocationJobs || {};
    window.relocationJobs.setFetchView = setFetchViewFn;
    if (window.relocationJobs._pendingFetchView) {
      setFetchViewFn(window.relocationJobs._pendingFetchView);
      window.relocationJobs._pendingFetchView = null;
    }
  }, [setFetchViewFn]);

  const headerMount = document.getElementById("fetch-header-root");
  const panel = fetchView.panel || {};

  return (
    <>
      {headerMount
        ? createPortal(<FetchHeader header={fetchView.header || {}} />, headerMount)
        : null}
      {createPortal(<FetchPanel panel={panel} />, document.body)}
    </>
  );
}

const boardMount = document.getElementById("jobs");
if (boardMount) {
  createRoot(boardMount).render(
    <StrictMode>
      <BoardRoot />
    </StrictMode>,
  );
}

createRoot(document.getElementById("fetch-panel-root") || document.body).render(
  <StrictMode>
    <FetchRoot />
  </StrictMode>,
);

function FetchHeader({ header = {} }) {
  if (!header.controlsEnabled) return null;

  if (header.showButton) {
    return (
      <button
        type="button"
        className={`header-secondary-btn${header.countryRequired ? " fetch-country-required" : ""}`}
        title={header.buttonTitle || "Fetch jobs for the selected country and ATS filter"}
        aria-disabled={header.countryRequired ? "true" : undefined}
        onClick={(e) => {
          e.stopPropagation();
          window.relocationJobs?.fetchActions?.startFetch?.();
        }}
      >
        <svg width="15" height="15" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
          <path d="M21 12a9 9 0 1 1-3-6.7" />
          <path d="M21 3v6h-6" />
        </svg>
        <span className="header-btn-text">Fetch</span>
      </button>
    );
  }

  if (!header.showChip) return null;

  return (
    <button
      type="button"
      className="header-secondary-btn fetch-progress-chip"
      title={header.chipTitle || "View fetch progress"}
      aria-label={header.chipTitle || "View fetch progress"}
      onClick={(e) => {
        e.stopPropagation();
        window.relocationJobs?.fetchActions?.openProgress?.();
      }}
    >
      <span className="fetch-progress-chip-meter" aria-hidden="true">
        <span
          className="fetch-progress-chip-fill"
          style={{ width: `${header.pct || 4}%` }}
        />
      </span>
      <span className="header-btn-text">{header.metaText || "Fetching…"}</span>
      <svg className="fetch-progress-chip-chevron" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" aria-hidden="true">
        <path d="M9 18l6-6-6-6" />
      </svg>
    </button>
  );
}

export default FetchHeader;

